// ── JSONL parsen ─────────────────────────────────────────────
const text = $input.first().json.stdout || '';

const alleObjekte = text
  .split('\n')
  .filter(l => l.trim())
  .map(l => { try { return JSON.parse(l); } catch(e) { return null; } })
  .filter(Boolean);

// ── Zwei-Stufen-Filter ────────────────────────────────────────
const TYPEN_HAUS    = ['einfamilienhaus','zweifamilienhaus','mehrfamilienhaus','doppelhaush','reihenhaus','wohn-/gesch'];
const TYPEN_GRUNDST = ['unbebautes grundst','baugrundst'];

const relevant = alleObjekte.filter(obj => {
  const typ = (obj.objekt_typ || '').toLowerCase();
  const vw  = obj.verkehrswert || 0;
  if (TYPEN_GRUNDST.some(t => typ.includes(t)) && vw >= 10000) return true;
  if (TYPEN_HAUS.some(t    => typ.includes(t)) && vw >= 50000) return true;
  return false;
});

// ── Deduplizierung via Static Data ────────────────────────────
const staticData   = $getWorkflowStaticData('global');
const bekannteKeys = staticData.seenKeys || [];

const neueObjekte = relevant.filter(obj => !bekannteKeys.includes(obj.key));

staticData.seenKeys = [...new Set([
  ...bekannteKeys,
  ...relevant.map(o => o.key)
])];

// ── HTML bauen ────────────────────────────────────────────────
const datum = new Date().toLocaleDateString('de-DE', { day:'2-digit', month:'2-digit', year:'numeric' });

const rows = neueObjekte.map(o => {
  const vw = o.verkehrswert
    ? (o.verkehrswert >= 1000 ? (o.verkehrswert / 1000).toFixed(0) + 'k EUR' : o.verkehrswert.toFixed(0) + ' EUR')
    : '–';
  const url = o.url
    ? `<a href="${o.url}" style="color:#2563eb;">Details</a>`
    : '–';
  return `
    <tr style="border-bottom:1px solid #e5e7eb;">
      <td style="padding:10px 12px;font-weight:600;color:#111827;">${o.objekt_typ || '–'}</td>
      <td style="padding:10px 12px;color:#374151;">${o.amtsgericht ? o.amtsgericht.replace(' in Niedersachsen','') : '–'}</td>
      <td style="padding:10px 12px;color:#374151;font-family:monospace;font-size:13px;">${o.aktenzeichen || '–'}</td>
      <td style="padding:10px 12px;color:#374151;">${vw}</td>
      <td style="padding:10px 12px;color:#374151;">${o.termin || '–'}</td>
      <td style="padding:10px 12px;">${url}</td>
    </tr>`;
}).join('');

const htmlBody = `<!DOCTYPE html>
<html lang="de">
<head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f9fafb;font-family:Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f9fafb;padding:32px 0;">
    <tr><td align="center">
      <table width="700" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.1);">

        <!-- Header -->
        <tr style="background:#1e3a5f;">
          <td colspan="6" style="padding:24px 28px;">
            <p style="margin:0;color:#93c5fd;font-size:13px;letter-spacing:.05em;">ZVG-SCRAPER · ${datum}</p>
            <h1 style="margin:4px 0 0;color:#ffffff;font-size:22px;font-weight:700;">
              ${neueObjekte.length} neue Zwangsversteigerung${neueObjekte.length !== 1 ? 'en' : ''}
            </h1>
            <p style="margin:4px 0 0;color:#bfdbfe;font-size:14px;">Region: Braunschweig · Gifhorn · Celle · Wolfsburg · Salzgitter · Helmstedt · Peine</p>
          </td>
        </tr>

        <!-- Tabelle -->
        <tr><td colspan="6" style="padding:0;">
          <table width="100%" cellpadding="0" cellspacing="0">
            <thead>
              <tr style="background:#f3f4f6;">
                <th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Typ</th>
                <th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Amtsgericht</th>
                <th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Aktenzeichen</th>
                <th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Verkehrswert</th>
                <th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Termin</th>
                <th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Link</th>
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </td></tr>

        <!-- Footer -->
        <tr style="background:#f9fafb;">
          <td colspan="6" style="padding:16px 28px;border-top:1px solid #e5e7eb;">
            <p style="margin:0;color:#9ca3af;font-size:12px;">Automatisch generiert · ZVG-Portal Scraper · Niedersachsen</p>
          </td>
        </tr>

      </table>
    </td></tr>
  </table>
</body>
</html>`;

return [{ json: { neueObjekte, anzahl: neueObjekte.length, htmlBody } }];

// neueObjekte-Array → einzelne Items für Google Sheets
return $input.first().json.neueObjekte.map(o => ({
  json: {
    key:             o.key,
    datum:           new Date().toLocaleDateString('de-DE'),
    aktenzeichen:    o.aktenzeichen || '',
    amtsgericht:     (o.amtsgericht || '').replace(' in Niedersachsen', ''),
    objekt_typ:      o.objekt_typ || '',
    verkehrswert_eur: o.verkehrswert || 0,
    termin:          o.termin || '',
    url:             o.url || ''
  }
}));
